def is_symmetric(matrix, n):
    for i in range(n):
        for j in range(n):
            if matrix[i][j] != matrix[j][i]:
                return False
    return True

def is_diagonal_zero(matrix, n):
    for i in range(n):
        if matrix[i][i] != 0:
            return False
    return True

def find_mst(matrix, n):
    # Create edges list
    edges = []
    for i in range(n):
        for j in range(i+1, n):
            edges.append((matrix[i][j], i, j))
    
    # Sort edges by weight
    edges.sort()
    
    # Union-Find data structure
    parent = list(range(n))
    
    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]
    
    def union(x, y):
        px, py = find(x), find(y)
        if px != py:
            parent[px] = py
            return True
        return False
    
    # Build MST adjacency list
    mst = [[] for _ in range(n)]
    
    for weight, u, v in edges:
        if union(u, v):
            mst[u].append((v, weight))
            mst[v].append((u, weight))
    
    return mst

def dfs(u, parent, mst, max_edge, root, weights):
    for v, w in mst[u]:
        if v != parent:
            if parent == -1:
                weights[v] = w
            else:
                weights[v] = max(weights[u], w)
            dfs(v, u, mst, max_edge, root, weights)

def compute_max_edge(mst, n):
    max_edge = [[0]*n for _ in range(n)]
    
    for i in range(n):
        weights = [0] * n
        dfs(i, -1, mst, max_edge, i, weights)
        for j in range(n):
            max_edge[i][j] = weights[j]
    
    return max_edge

